/**
 * This module provides a standardized way to send HTTP requests within the Postman sandbox.
 */
class ApiClient {
    /**
     * Sends an HTTP request using Postman pm.sendRequest
     * @param {Object} options - Request configuration (method, url, headers, body, queryParams)
     * @param {Function} callback - Postman callback function
     */
    send(options, callback) {
        const { method, url, headers, body, queryParams } = options;

        const request = {
            url: this._buildUrl(url, queryParams),
            method: method || 'GET',
            header: headers || {},
            body: body ? {
                mode: 'raw',
                raw: typeof body === 'string' ? body : JSON.stringify(body),
                options: {
                    raw: {
                        language: 'json'
                    }
                }
            } : undefined
        };

        pm.sendRequest(request, callback);
    }

    _buildUrl(baseUrl, queryParams) {
        if (!queryParams) return baseUrl;
        const query = Object.keys(queryParams)
            .map(key => `${encodeURIComponent(key)}=${encodeURIComponent(queryParams[key])}`)
            .join('&');
        return `${baseUrl}${baseUrl.includes('?') ? '&' : '?'}${query}`;
    }
}


/**
 * Dynamic Request Builder
 * 
 * Builds API requests with environment-aware configurations.
 */
class RequestBuilder {
    constructor(baseUrl) {
        let base = baseUrl || pm.environment.get('baseUrl') || '';
        this.baseUrl = base.replace(/\/+$/, '');
    }

    build(endpoint, method = 'GET', options = {}) {
        const cleanEndpoint = endpoint.replace(/^\/+/, '');
        const finalUrl = `${this.baseUrl}/${cleanEndpoint}`;

        return {
            method: method,
            url: finalUrl,
            headers: options.headers || { 'Content-Type': 'application/json' },
            body: options.body,
            queryParams: options.queryParams
        };
    }
}

if (typeof module !== 'undefined') {
    module.exports = RequestBuilder;
}


/**
 * Generic Response Validator
 * 
 * Standardized assertions for API responses.
 */
class ResponseValidator {
    /**
     * Asserts internal status code
     * @param {number} code 
     */
    static assertStatusCode(code) {
        pm.test(`Status code is ${code}`, () => {
            pm.response.to.have.status(code);
        });
    }

    /**
     * Asserts field existence in response body
     * @param {string} fieldName 
     */
    static assertFieldExists(fieldName) {
        pm.test(`Response contains field: ${fieldName}`, () => {
            const jsonData = pm.response.json();
            pm.expect(jsonData).to.have.property(fieldName);
        });
    }

    /**
     * Asserts field type
     * @param {string} fieldName 
     * @param {string} type - 'string', 'number', 'boolean', etc.
     */
    static assertFieldType(fieldName, type) {
        pm.test(`${fieldName} should be of type ${type}`, () => {
            const jsonData = pm.response.json();
            pm.expect(jsonData[fieldName]).to.be.a(type);
        });
    }

    /**
     * Asserts response body structure matches expected keys
     * @param {string[]} requiredKeys 
     */
    static assertStructure(requiredKeys) {
        pm.test('Response structure is valid', () => {
            const jsonData = pm.response.json();
            requiredKeys.forEach(key => {
                pm.expect(jsonData).to.have.property(key);
            });
        });
    }
}


/**
 * JSON Schema Validation Engine
 * 
 * Validates responses against provided JSON schemas.
 */
class SchemaValidator {
    /**
     * Validates a JSON schema
     * @param {Object} schema - JSON schema object
     * @param {Object} data - Optional data to validate (defaults to pm.response.json())
     */
    static validate(schema, data) {
        pm.test('Response schema is valid', () => {
            const traceData = data || pm.response.json();
            pm.expect(traceData).to.have.jsonSchema(schema);
        });
    }
}


/**
 * Reusable Test Data Factory
 * 
 * Generates random, domain-independent test data.
 */
